INSERT INTO "payload"."posts" ("id", "title", "slug", "status", "content", "description", "image_id", "image_id_id", "featured_image_id", "featured_image_id_id", "published_at", "updated_at", "created_at", "downloads_id") VALUES
	('8d2e1b21-0eeb-4942-a6df-750b163fb2fe', 'Pitch Deck: How To Create The Perfect Funding Proposal', 'pitch-deck', 'published', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Whether you are a startup founder, business owner or a ''corporate entrepreneur'', your pitch deck is kind of important - after all, it captures your rationale for why people should invest in your idea and give you a lot of money. Maybe millions. So your investor pitch, and supporting pitchdeck, better nail it. But for every venture capitalist or angel investor out there, there is a different opinion on exactly how to approach the investor pitch deck. 6 slides? 10 slides? 15 slides? No slides, just a killer demo? *I have never seen a presentation* *that* *has too few slides, too big a font, and too little graphics.* Guy Kawasaki, Venture Capitalist *You can explain your startup in mind numbing* *detail or you* *can inspire an investor and let them imagine.* *Guess what* *works* *better?* *When* *you sit down and build your investor deck, think of* *six* *slides* *that will inspire* *and leave something for the imagination.* Fred Wilson, Venture Capitalist *The* *most fundamental strategy of a startup is* *the* *financing strategy.* *If your* *company runs out of finance it will close* *no* *matter how good the product* *strategy is.* Reid Hoffman, Entrepreneur, Venture Capitalist *[A ten section]* *business plan format, within 15GÇô20 slides,* *is all* *thatGÇÖs needed.* Sequoia Capital, Venture Capitalists In this post we provide the authoritative consensus on the slides you need in your business funding pitch. We have looked at what the world''s most influential venture capitalists, entrepreneurs and angel investors, including [Guy](https://guykawasaki.com/) [Kawasaki](https://guykawasaki.com/), [Reid](https://en.wikipedia.org/wiki/Reid_Hoffman) [Hoffman](https://en.wikipedia.org/wiki/Reid_Hoffman), [Fred](https://avc.com/) [Wilson](https://avc.com/), [Brad Feld](https://feld.com/), [Mark](https://bothsidesofthetable.com/) [Suster](https://bothsidesofthetable.com/) and Dave McClure, look for in a pitch deck (it is a veritable who''s who of Silicon Valley VCs). We have then summarized that advice on pitching investors into an easy to follow plan. ## **What is a pitch deck?** A pitch deck is a brief, written presentation that supports your oral, fundraising sales presentation. It is a business pitch. The objective of a powerful pitch deck is to concisely layout the rationale for investing in your business (the investment opportunity). After canvassing leading entrepreneurs and investors, the consensus set of investor pitch deck slides are: - Company Purpose (The Title slide) - The Problem - The Solution (and your Demo) - The Market - The Competition - The Value Proposition - The Business & Revenue Model - The Team - The Financials - Current Status & Use of Funds In the rest of this article we explore each of these slides in detail, providing advice and examples of what to include, and what not to. We also look at how your pitch approach must change depending on what stage your idea or company is at. We discuss pitch requirements for startup seed pitches, series A and B pitches, and IPO roadshow decks. ### **When do you need a pitch deck?** A pitch deck lets you present your business plan to potential investors when new funding is needed to develop the business. You donGÇÖt need a pitch deck to attract funding if your business is successful, growing organically and at the right level and scale for the market and your ambitions. ### **What are you** **trying to achieve with your pitch deck?** Your goal is to persuade investors to put money into your business, to fund your business''s growth. The funds are used to push your business to the next stage of its development. Pitch decks are the tool to convince investors of the merits of funding your tech startup or business. ### **Who is your audience and what are their questions?** > *The* *classic partner in a VC firm is exposed to 5,000 pitches in a single year.* > > *Reid Hoffman, Entrepreneur, Venture Capitalist* At SlideHeroes we provide presentation training on how to develop McKinsey presentations that focuses on: - Identifying your audience,\\ - &nbsp; Determining the question in the   mind of the audience that you are there to answer, and then - &nbsp; Structuring   a clear answer to that question #### **Your Audience** Your pitch deck target   audience is any potential investor who provides investment for new business   ideas (Venture capital, see funding). This will typically be VCs or angel   investors and their question will be ''Why is this company worth investing in?''   While this may seem obvious (it is), a surprising number of pitches can lose   sight of this fundamental question. Focus on answering this exam question. It is   worth noting that fundraising from angels and venture capital is tough. -   &nbsp;&nbsp;**Competition is fierce:**&nbsp;VCs are exposed to thousands of   pitches a year, and may only make a few investments.\\ - &nbsp; **Venture**   **Capitalists are looking for significant returns:** Because startup investing   is risky (90% of investments fail), VCs must compensate for these losses with a   few big wins. As a consequence, venture capitalists are looking for investments   that have the potential to return at least 10x the initial investment. - &nbsp;   **Venture Capitalists specialize:**&nbsp;VCs tend to specialize in particular   areas where they either have expertise or a strong investment thesis. As a   consequence, fit between investor and startup is critical. Look for quality over   quantity of investors.&nbsp;Research your target investor and see if they invest   in the sector you are in or the stage of company you are at. Tailor your story   to the particular investment theses or sector focus of the VC you are speaking   to. Research past investments to understand what ideas resonate with your   audience. Michael Wolfe says you must get across how GÇŁthis company is going to   become more valuable in the future.GÇĄ As Reid Hoffmann explains, when pitching   LinkedIn, GÇŁMy strategy was to steer immediately into the revenue question   because that was investorsGÇÖ biggest concern in 2004.GÇĄ ### **What do you**   **absolutely need in your pitch deck?** Research from Professor Tom Eisenmann   from the Harvard Business School for [Docsend](https://docsend.com/view/p8jxsqr)   looked at the fundraising of 200 start-ups as they went through the seed and   series A funding process, raising over $360 million. It found that: - &nbsp; The   financial and team slides were viewed the most and longest at 23.3 and 22.8   seconds each on average\\ - &nbsp; The problem and solution pages were viewed for   the least length of time at 11.3 and 10.6 seconds - &nbsp; Avoid listing deal   terms and funding information in your deck, instead deliver them in person (they   will vary for each investor) ## **Seed,** **Series A, Series B and IPO**   **Fundraising Rounds** Michael Wolfe puts it best when he states: GÇŁThe pitch   deck you used for a seed round will not be what you need for series A or B   pitches. Your business will have changed, the market too and what you want to   get out of the investor meetings.GÇĄ Broadly speaking, there are four types of   pitches related to businesses at different stages of development. ### **1. The**   **''Seed** **Round'' pitch deck** A seed-round pitch deck is a pitch for initial   funding from startup investors. The seed investment round can often come before   you have a product for sale or any revenue. The focus of the pitch is typically   on the problem being solved, the size and potential of the market, and how   compelling the solution and business model is. Seed investors are typically   small venture capital funds that give between $250k - $1m. Angel investors,   wealthy individuals investing their money directly (angel investment), are also   an important source of capital at this stage of fundraising. There are important   differences between these two sets of audiences, and as a consequence, what they   are looking for from a pitch. Angel investors typically invest, in aggregate,   substantially less than VCs (even micro-VCs specializing on seed rounds). As a   consequence they are likely to take more of a personal interest in the founders   and the business and be in a position to offer a more hands on role in advising   the company. But they will be unlikely to invest in follow-on rounds due to   their capital constraints. Their focus is typically on understanding the   entrepreneurs vision for the product and commercial opportunity. > *The biggest*   *mistake presenters make is that they think that they are so interesting and*   *have* *so much to say that they are the exception to the ''less is more'' theory*   *of* *presentations.* > > *Guy Kawasaki, Venture Capitalist* ### **2. The**   **''Series** **A** **Round'' pitch deck** With a Series A funding round, the   business has typically figured out product/market fit and are now looking for   money to: - &nbsp;&nbsp;Figure out or scale distribution,\\ - &nbsp; Master a   revenue or business model, or - &nbsp; Adapt a business model to new markets As   a consequence of this change in objective, the focus of the Series A pitch deck   changes as well. The pitch deck must: - &nbsp; Demonstrate how the product fits   into a target market\\ - &nbsp; Show investors how funds will enable the company   to master a business model, or - &nbsp; Show investors how more funds will lead   to more customers, quicker The investor profile may change in this round. Some   investors specialize in follow-on rounds, others in very early stage   investments.&nbsp;Do your research and tailor your story to the questions the   prospective investor will prioritize. ### **3. The ''Series B Round'' pitch deck**   A Series B pitch deck focuses on scaling the business. You have a user base,   customers and growing revenue helped by earlier funding. New funds are used to   scale the business model, make further acquisitions and invest in key   capabilities. - &nbsp; The focus shifts from describing the vision and concept   to providing evidence that you have a viable business\\ - &nbsp;&nbsp;The pitch   should include details of what you have achieved with funding from earlier   investment rounds\\ - &nbsp; It should offer a more mature view of the market,   revenue model and competition - &nbsp; The focus should be on sustainable growth   models that drive scale ### **4. The ''IPO'' Roadshow Document** Series C pitch   decks and on-wards, including IPO roadshow decks, seek funding to expand, often   into new geographies or adjacent markets. - &nbsp; At this stage the company has   been very successful and has proven its viability\\ - &nbsp; The IPO process is   usually managed by investment banks, who will develop extensive material to   support the investment process - &nbsp; IPO decks tend to be a longer and   contain significantly more financial detail - &nbsp; But, as with pitch decks   for earlier stage companies, clarity of message remains paramount ## **The**   **Perfect Pitch Deck: The Consensus View** Based on the research we have   conducted, these are the 10 slides you need. The optimum time for a pitch,   according to Kawasaki and Suster, is 20 minutes. If your business has certain   problems that, at this stage of its development, are still awaiting answers -   confront them head on. Address these issues directly because you can be sure   your potential investors will. > *The best pitch is a conversation. It should*   *be* *cohesive, tell a story and explain a trend.* > > *Mark Suster, 2X*   *Entrepreneur,* *Venture Capitalist* ### **Slide 1: Company Purpose**", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}]}], "direction": "ltr"}, "chunks": [], "config": {"theme": {"text": {"bold": "lexical-bold", "code": "lexical-code", "italic": "lexical-italic", "subscript": "lexical-subscript", "underline": "lexical-underline", "superscript": "lexical-superscript", "strikethrough": "lexical-strikethrough", "underlineStrikethrough": "lexical-underlineStrikethrough"}}, "namespace": "lexical"}, "format": "", "version": 1, "syncedChunksData": {}, "downloadedDataVersions": []}', '', '22cfd1ad-0d53-4d53-b1d0-9fb0624e872c', '22cfd1ad-0d53-4d53-b1d0-9fb0624e872c', NULL, NULL, '2024-08-19 00:00:00+00', '2025-04-15 18:51:53.79+00', '2025-04-15 18:51:53.79+00', NULL),
	('994640a9-4e21-4ff4-8adf-b69189364dfe', 'In Defense of PowerPoint', 'powerpoint-presentations-defense', 'published', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "PowerPoint has a bad rep. > PowerPoint... is evil. > > *Edward Tufte, Author of* *The Cognitive Style of PowerPoint*", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}]}], "direction": "ltr"}, "chunks": [], "config": {"theme": {"text": {"bold": "lexical-bold", "code": "lexical-code", "italic": "lexical-italic", "subscript": "lexical-subscript", "underline": "lexical-underline", "superscript": "lexical-superscript", "strikethrough": "lexical-strikethrough", "underlineStrikethrough": "lexical-underlineStrikethrough"}}, "namespace": "lexical"}, "format": "", "version": 1, "syncedChunksData": {}, "downloadedDataVersions": []}', 'PowerPoint on Trial', '1e294d7b-1d01-4a63-b815-f98f21a32a16', '1e294d7b-1d01-4a63-b815-f98f21a32a16', NULL, NULL, '2024-04-11 00:00:00+00', '2025-04-15 18:51:53.861+00', '2025-04-15 18:51:53.861+00', NULL),
	('671d387f-8f55-48ac-965e-c38e5e056eb4', 'The Art & Craft of Business Presentation Design', 'art-craft-business-presentation-creation', 'published', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "## {% highlight variant=\"blue\" %}Welcome to SlideHeroes{% /highlight %} We are absolutely thrilled you stopped by! We are SlideHeroes, an online video course dedicated to helping you create killer presentations. Presentations of a particular style, though. The sit-down, business style presentations you give every day. SlideHeroes provides online training to professionals looking to learn to create compelling business presentations. Our training is online and video-based. And we are pretty proud of it. ## Our Mission Our mission (and our commitment) is to teach professionals how to craft compelling and effective GÇ˙sit-down-styleGÇÖ presentations GÇô and to help as many of you as we can create the powerful presentations you need to be successful. This blog will be dedicated to doing just that. Our blog provides a window into how we think about presentations and the approach we think works best for creating great ones. It also provides a great taste of the kind of content found in our course. Our video course is the best source of presentation training on the internet. At least we think so! Try our free trial and see for yourself! {% cta    ctatext=\"Ready to get started?\"    ctadescription=\"Join hundreds of satisfied customers and take your presentations to the next level.\"    ctabuttontext=\"Start your free trial\" /%} The course features: - Instant access to 20 comprehensive video lessons - A structured, guided curriculum with over 4 hours of video training - 20 detailed unit outlines and accompanying presentation slides - Free PowerPoint presentation template (over 1,000 slides) - 30-day money-back guarantee I hope you find tremendous value in our content. To your success! #### Michael&nbsp;", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}]}], "direction": "ltr"}, "chunks": [], "config": {"theme": {"text": {"bold": "lexical-bold", "code": "lexical-code", "italic": "lexical-italic", "subscript": "lexical-subscript", "underline": "lexical-underline", "superscript": "lexical-superscript", "strikethrough": "lexical-strikethrough", "underlineStrikethrough": "lexical-underlineStrikethrough"}}, "namespace": "lexical"}, "format": "", "version": 1, "syncedChunksData": {}, "downloadedDataVersions": []}', 'The first post of our blog. What it takes to navigate the art and science of designing business presentations.', 'b0175b34-3580-41a4-b6ad-d4a7f8fca845', 'b0175b34-3580-41a4-b6ad-d4a7f8fca845', NULL, NULL, '2024-04-10 00:00:00+00', '2025-04-15 18:51:53.771+00', '2025-04-15 18:51:53.771+00', NULL),
	('55cd8bda-9acb-4fc2-b6e9-afa93b5fd012', 'Presentation Teardown: BCG Presentation Review', 'presentation-review-bcg', 'published', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "## **Presentation Teardown: ConsultantGÇÖs Tricks Exposed** In this post we conduct a GÇ˙teardownGÇÖ of a presentation from Boston Consulting Group, exploring what it does well and making some suggestions in areas where there may be room for improvement. BCG and [McKinsey presentations](https://www.slideheroes.com/mckinsey-business-presentations.html) have a particular style which you can read about more [here](https://www.slideheroes.com/mckinsey-business-presentations.html). They tend to be highly structured and analytical. This presentation is made available to the public on [BCGGÇÖs website](https://www.bcgperspectives.com/content/Slideshow/information_technology_strategy_digital_economy_data_privacy_by_the_numbers/#ad-image-0) and on [slideshare.com](https://www.slideshare.net/TheBostonConsultingGroup/data-privacy-by-the-numbers). You can flip through the entire presentation using the presentation slider below. <slider? Alternatively, here is a video: <video> BCGGÇÖs presentation GÇ˙Data Privacy by the NumbersGÇÖ is designed to provide a perspective on personal data privacy GÇô provoking and answering an important question: How private do people consider their personal data, and what does that mean for business? ![](/site/images/presentation-review-bcg/Slide3.webp) This presentation is BCGGÇÖs answer to that question. The presentation concludes by planting a final question in the mind of the audience (what do we do?) which, BCG hopes, will drive sales of consulting work. ![](/site/images/presentation-review-bcg/Slide5.webp) I like the title GÇ˙Data Privacy by the NumbersGÇÖ. ItGÇÖs snappy, a little clever. Often the more effective presentation title is the one which directly speaks to the question the presentation is meant to answer. Every audience is thinking GÇ˙What Is In It For MeGÇÖ at the start of a presentation (why should I bother to listen?). A title which promises an answer to a question that the audience has is the perfect way to alleviate those concerns. An alternative could have been: GÇ˙Data Privacy: The markets, industries and data types that matter mostGÇÖ ![](/site/images/presentation-review-bcg/Slide7.webp) When done well, summaries like this one can be a great addition. BCGGÇÖs summary does a great job of being brief and signposting the key points to come in the presentation. You want to avoid re-writing the entire presentation in the summary. ![](/site/images/presentation-review-bcg/Slide9.webp) Consulting presentations like this one tend to be heavily footnoted. This is a good thing. Footnotes provide credibility. More importantly, when you cite numbers and statistics (as BCG will do extensively in this presentation) you need to say where you got the data from. Not providing footnotes is, at best, lazy, and at worst, dishonest. ![](/site/images/presentation-review-bcg/Slide11.webp) The text on this page could do with more whitespace to improve scannability. Increasing the spacing between the paragraphs would help a lot. A subtle thing, but it would help. The GÇ˙Draft GÇô for discussion onlyGÇÖ label at the bottom of the slide should really be tossed. It has dubious legal weight. The deck is on their website, so it is clearly no longer a GÇ˙draftGÇÖ. Often labels like this are repeated on every slide. Try and avoid this, as it creates a ton of visual noise that does nothing but distract the reader. I recommend keeping the visual elements that you repeat from slide to slide to an absolute minimum. ![](/site/images/presentation-review-bcg/Slide13.webp) This slide is providing the critical context every introduction needs.&nbsp;The Authors do a good job of starting in the right place, with data and perspectives that most people will assume they already know (personal data privacy, for most people, is a top issue).&nbsp;This is a critical foundation for the argument to come. ![](/site/images/presentation-review-bcg/Slide16.webp) I like the headline style BCG has adopted GÇô a pithy top-line label with a descriptive second line. The second line is absolutely key. You want to ensure that your headline clearly lays out the take-away of your slide. This helps the audience tremendously in understanding what it is the slide is trying to say. ![](/site/images/presentation-review-bcg/Slide17.webp) BCG has not really utilized any storytelling techniques in this presentation. To be fair, storytelling is not a very common technique within consulting and is one that often works better orally. Having said that, I think this topic presents a real opportunity to wrap a story around the issue of personal data privacy. It is an emotionally charged subject. Storytelling techniques could really bring this personal dimension into focus. ![](/site/images/presentation-review-bcg/Slide18.webp) This is a really minor quibble. With survey data it is usually a good idea to state the size of the survey population (n). The bigger the n, the more confidence I have as a reader that we can actually believe these numbers. So, a minor point, but the kind of thing that comes up as a question in presentations. Oftentimes, it is just easier to anticipate the question, and provide the answer in the footnotesGÇŞ ![](/site/images/presentation-review-bcg/Slide20.webp) The strength of this slide is that it attacks and rebuts a hypothesis the audience may have started to formulate in their headGÇŞ GÇ˙Yes, but older people sure donGÇÖt have the same attitudes as younger generationsGÇŞGÇÖ ![](/site/images/presentation-review-bcg/Slide22.webp) The interesting thing to note in this business chart is the chart design. BCGGÇÖs goal is to emphasize the similarity of the numbers and visually disguise the delta (to reinforce their conclusion, captured in the headline, that age doesnGÇÖt really tell us much). Notice how the length of the bars have been lengthened as much as possible? The delta in the UK of 16% sure seems material to me. But it is a good story. ![](/site/images/presentation-review-bcg/Slide24.webp) This is where the complication in the story is introduced.&nbsp;So far the data that has been shared has really reinforced what we already either know or assume: - Everyone agrees privacy of personal information is important (all countries, all ages) - **But**, there are big differences in perceived privacy across various data types ![](/site/images/presentation-review-bcg/Slide26.webp) I like the choice of a heat map to display this data. Using red to represent the more GÇ˙PrivateGÇÖ data types is a subtle, smart choice. ![](/site/images/presentation-review-bcg/Slide28.webp) Lots of great data here, displayed clearly. ![](/site/images/presentation-review-bcg/Slide30.webp) This is a really beautiful slide. I love bubble charts. ![](/site/images/presentation-review-bcg/Slide31.webp) Unfortunately, this chart type really is not the best choice. Visually the chart is emphasizing the correlation (the line your eye draws from bottom left to right) between the data types developed markets view as risky and data types rapidly developing markets view as risky. Or, put another way, developed and rapidly developing have the same views. Unfortunately, that point was more clearly communicated on the previous two slides. A bar chart would have more effectively shown the % difference between developed and developing countries. ![](/site/images/presentation-review-bcg/Slide33.webp) This slide makes an important connection between concerns about privacy of personal data and the custodial responsibility of business in various industries.\\ ![](/site/images/presentation-review-bcg/Slide37.webp) So these spiral charts are pretty to look at, but I am not a fan. It is extremely difficult to actually see in the data the point that is being made in the headline. That is a cardinal sin when presenting data. Each industry is colored a different color depending on market GÇô not helpful. ![](/site/images/presentation-review-bcg/Slide38.webp) A better approach would have been to highlight the online, telecom and financial industries and highlight them a bright color, while highlighting the rest of the industries and more neutral color. ![](/site/images/presentation-review-bcg/Slide40.webp) This slide is clever. It is a very nice segue towards the GÇ˙what do we do about this?GÇÖ next steps part of the presentation that is so critical (as advice on that question is what BCG is selling). The story so far: 1. Personal data is important (Knew that already, but thanks) 1. All ages and developed markets care about this (thatGÇÖs interesting) 1. What people consider private varies considerably by data type (very interesting.&nbsp;big implications) 1. or private data, we need to provide simple tools (that is insight I can use, but what about the less private dataGÇŞ ![](/site/images/presentation-review-bcg/Slide42.webp) And here is your answer! Create the GÇ˙Trust AdvantageGÇÖ! Ummmm. How do I do that? Simple. Call BCG.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}]}], "direction": "ltr"}, "chunks": [], "config": {"theme": {"text": {"bold": "lexical-bold", "code": "lexical-code", "italic": "lexical-italic", "subscript": "lexical-subscript", "underline": "lexical-underline", "superscript": "lexical-superscript", "strikethrough": "lexical-strikethrough", "underlineStrikethrough": "lexical-underlineStrikethrough"}}, "namespace": "lexical"}, "format": "", "version": 1, "syncedChunksData": {}, "downloadedDataVersions": []}', 'A GÇ˙teardown'' of a presentation from Boston Consulting Group, exploring what it does well and making some suggestions on areas where there may be room for improvement.', '8642fb5a-84a0-4a1f-975d-bb99a152e018', '8642fb5a-84a0-4a1f-975d-bb99a152e018', NULL, NULL, '2025-04-15 18:51:53.876+00', '2025-04-15 18:51:53.877+00', '2025-04-15 18:51:53.877+00', NULL),
	('c4d062b6-d23e-4b51-a18f-932f2a65906c', 'Presentation Tips: Mistakes that will get you Fired', 'presentation-tips', 'published', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The vast majority of business presentations suck. We know this. Usually we blame bad PowerPoint. This article provides presentation tips on 10 mistakes we should avoid accidentally making. ThereGÇÖs lots of presentation tips out there meant to help us. But if you work in corporate America, I would suggest you ignore most of it because most GÇ˙business presentation adviceGÇÖ doesnGÇÖt focus on presentations, it focuses on speeches. I donGÇÖt know about your experience, but my boss gets pissed off when I try to give speeches on quarterly financial performance. He gets especially annoyed when I channel JFK, slip into a Bostonian accent and declare that: *We choose to make this investment in this* *decade and do the other things, not because they are easy, but because they* *are* *hardGÇŞ* John F. Kennedy (never) Ya, that will get you fired. Ya, that will get you fired. GÇ˙Business presentationsGÇÖ are not speeches, but they are how we communicate. They are the lingua franca of corporate America. They combine words, images and delivery to communicate our message. And they are hard. Why? Because being great at communication has always been hard. Here are ten presentation tips: other mistakes that, if they donGÇÖt get you fired, will hurt your career or, at the very least, make you look like an idiot. ## Presentation Tip (Mistake) #1: Equating a Business Presentation with an opportunity to GÇ˙wing-itGÇÖ *All the so-called GÇ˙secrets of successGÇÖ will not work unless you do.* Author Unknown, (smart person) Really the only place to start. A simple truth. If your meeting is important enough to prepare a presentation for, it is important enough to prepare a great presentation for. Put in the effort. If you donGÇÖt, you have no one to blame but yourself. I wonGÇÖt belabor this. It is assumed. ### To Do: Put in the work ## Presentation Tip (Mistake) #2: Worrying about your opening joke, your GÇ˙introGÇÖ, your hair This is not a performance. It is business. Your presentation to your board, boss, customer, or investor is not a TED Talk. It is not a speech. It is not public speaking. GÇ˙Sit-downGÇÖ McKinsey-style business presentations around a board table are fundamentally different to public speaking and require a completely different approach to communication. They require: - That your message is written down. Not every word. Just enough that you arenGÇÖt needed. - Clarity of purpose, tailored to the need of your audience (what is their question?) - Transparent, ruthless structure (a well constructed answer) - Facts, in high resolution - Style, minimalist is design ### To DoGÇÖs: - Write, write, write - Rewrite - Focus on structure - DonGÇÖt be the joke. Skip the joke ## Presentation Tip (Mistake) #3: Not identifying the GÇ˙Power Behind The ThroneGÇÖ Who is your audience? Who has power? Who makes decisions? Sometimes it is not clear who the real decision makers are, or where power lies. This is especially true when you are presenting to a group, are an GÇ˙outsiderGÇÖ or are not part of the company. Once you have identified who you are really speaking to, determine what they are like. How do they like to consume information? What is the best way to reach them? ### To Do: - Profile your Audience GÇô understand the power, personality, communication preferences and sources of resistance amongst your audience (who you are really presenting to, what are they like) ## Presentation Tip (Mistake) #4: Presenting a topic, rather than answering a question What Is In It For Them? The most effective formula to ensuring your audience connects with your material and is engaged with your presentation is to give a presentation about something they care about. The best way to do this is to answer a question that they have. Rather than presenting about GÇ˙Customer Relationship Management SoftwareGÇÖ, instead a presentation that answers the question GÇ˙Our CRM software is old, does it need to be replaced?GÇÖ will prove to be much more relevant and topical for the audience. Here are a couple of examples: - **Question:** GÇ˙Do I have the problem your product solves?GÇÖ - **NOT Topic:** GÇ˙This is what our product doesGÇÖ or - **Question:** GÇ˙What is the best plan for accelerating growth?GÇÖ - **NOT Topic:** GÇ˙2022 Marketing PlanGÇÖ This process will very often result in much greater clarity around what EXACTLY the presentation should focus on. The topic Customer Relationship Management Software could, for example, answer: - GÇ˙Our CRM Software is old, does it need to be replaced?GÇÖ, or - GÇ˙Our CRM software is inefficient and needs to be replaced, how do we go about installing and selecting an alternative?GÇÖ The resulting presentations for each of these questions, as you can image, would be very different. ### To DoGÇÖs: - Always present a GÇ˙topicGÇÖ that is the answer to a question that is in the mind of your audience - Plant the question in the mind of the audience before answering it ## Presentation Tip (Mistake) #5: Not having an introduction There are many ways to start a presentation. The best approach for business presentations is with an introduction that is designed to plant the question you are there to answer into the minds of the audience. To do this: 1. Craft an introduction that outlines the background, or context, of the situation. Include all facts that are already known to your audience 1. Next, present the catalyst that has resulted in your audience having a question. The catalyst is what has changed or happened that has given rise to a question 1. Then, explicitly or implicitly state the question 1. Spend the rest of your presentation answering the question. Use Barbra MintoGÇÖs SCQ framework to help you. ### To DoGÇÖs: Craft an introduction that lays out the background and catalyst for the presentation Ensure the introduction GÇ˙tees-upGÇÖ the question you are planning on answering ## Presentation Tip (Mistake) #6: Failing to structure your argument Your job is to communicate your answer to your audienceGÇÖs question. When the audience cannot follow your logic, or the flow of your argument, they become frustrated. They get pissed off. They stop paying attention to you. Your audience wants to follow what you are saying; the logic of your argument. But they need your help. Structure is how you signpost where you are going and help your audience internalize what you are saying. Listen, structure is a good thing. But sometimes it just isnGÇÖt easy. Expect half your time to be spent working on structure. ### To DoGÇÖs: - Adopt common presentation structure blueprints - Focus on structure obsessively - Apply MECE principles (mutually exclusive, collectively exhaustive) - Limit your lists to no more than 5 items. If you have more, bucket these ideas into a new set of groupings, one level of abstraction higher ## Presentation Tip (Mistake) #7: Only asserting; failing to demonstrate You know what they say about opinions. And everyone has one. Your credibility skyrockets when you demonstrate the truth of your assertions through data, facts, or very compelling logic. Data is a good thing. Footnotes are a good thing. Use them. ### To-DoGÇÖs: - Use data, lots of it - Make sure the data is correct! Triple check. - When presenting data, make sure your business charts tell the truth (and do not distort the data in unintended ways) - Eliminate Chart Junk ## Presentation Tip (Mistake) #8: Underestimating or overestimating the role of design Design is important. It just isnGÇÖt everything. Your objective is not to create a pretty deck. The objective is to communicate your point (your answer to your audienceGÇÖs question). Having said this, design matters. The medium is the message. I canGÇÖt take you seriously if you canGÇÖt be bothered to make your deck look good. Because it really isnGÇÖt that hard to meet a minimum standard. But donGÇÖt allow design to get in the way of communicating your point, presenting your data. Adopt a minimalist design ethos GÇô not because it is inherently superior, but because it strips out the extraneous. It allows us to focus on that which is most important. ### To DoGÇÖs: - Recognize that many people think visually GÇô Explain concepts and ideas with pictures as well as text - Get yourself a good looking template, that is minimalist in design (Use the SlideHeroes template, its free; or checkout GraphicRiver - Adopt a message driven slide layout: Reserve each slide for a single primary idea; write concise two line headlines that make your main assertion or introduce your primary idea - DonGÇÖt use pie charts, crazy animations, 3D, or random special effects. Just donGÇÖt. - Create slides that are scannable GÇô Employ the three second rule GÇô people should be able to GÇ˙getGÇÖ the slide in 1, 2, 3 seconds ## Presentation Tip (Mistake) #9: Not worrying about your hair Have I convinced you of the fundamental differences between sit-down business presentations and public speaking? Good. Now ignore what I said. Because you better believe business presentations are a performance. Just not in the same way speeches are. And Performance is certainly NOT where you should start. But once your deck is in place, once your answer to the question is nailed, a focus on your performance in the room can make a huge difference. ### To DoGÇÖs: - Develop a script - Practice, practice, practice - Be yourself - Communicate with body and voice - Plan for answering questions - Have conviction in the material you are presenting. If you donGÇÖt, work harder. Demonstrate passion and enthusiasm. If you are not feeling it, drink some coffee. Fake it. If you canGÇÖt fake it, have someone else present - Manage public speaking anxiety with these tips ## Presentation Tip (Mistake) #10: Not having next steps You need next steps. You need a call to action. The objective of your presentation should be for your audience to DO SOMETHING as a result of you presenting your material. Examples of possible next steps include: - Try your product - Move to the next stage in your sales funnel - Go away to get the necessary investment to do what youGÇÖre recommending - Approve a course of action Identify what your Next Step is early in your process, make sure it strongly influences your approach to creating your presentation, and make sure the finished product compels your audience to take that step. ### To DoGÇÖs: - Identify what your desired next step(s) are early on in the development process - Design the presentation so that the next steps are articulated and are the expected, logical consequence of your answer you have presented Design the presentation so that the next steps are: - Articulated - The expected, logical consequence of your answer - Desirable GÇô your audience wants to do them ## Conclusion Sit-down business presentations are hard. And it is very easy to fall into any number of traps and create something that fails to deliver. But with effort, and focus on the right things (these 10 presentation tips), your presentation can become something that will get you noticed, get your point across, and progress your career.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}]}], "direction": "ltr"}, "chunks": [], "config": {"theme": {"text": {"bold": "lexical-bold", "code": "lexical-code", "italic": "lexical-italic", "subscript": "lexical-subscript", "underline": "lexical-underline", "superscript": "lexical-superscript", "strikethrough": "lexical-strikethrough", "underlineStrikethrough": "lexical-underlineStrikethrough"}}, "namespace": "lexical"}, "format": "", "version": 1, "syncedChunksData": {}, "downloadedDataVersions": []}', '10 Business Presentation Mistakes That Will Get You Fired, Demoted or Ignored', 'dc4dcdfd-00b9-442b-9b9b-4e4f52d844a2', 'dc4dcdfd-00b9-442b-9b9b-4e4f52d844a2', NULL, NULL, '2025-04-15 18:51:53.936+00', '2025-04-15 18:51:53.937+00', '2025-04-15 18:51:53.937+00', NULL),
	('bd812cdd-74df-4e32-92e6-0694123091f9', 'Public Speaking Anxiety: 8 Steps for Controlling the Fear', 'public-speaking-anxiety', 'published', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "## **It often begins with butterflies** In the pit of your stomach. Then, your heart begins to race. Your head starts to swim. Your palms start to sweat. Not the first-blush of love. Not the excruciating climb to the top of a roller-coaster. The fear of public speaking. Public speaking anxiety. For near 30% of Americans, it doesnGÇÖt get worse than public speaking. In fact according to the [Chapman UniversityGÇÖs Survey on](https://www.chapman.edu/wilkinson/research-centers/babbie-center/survey-american-fears.aspx) [American](https://www.chapman.edu/wilkinson/research-centers/babbie-center/survey-american-fears.aspx) [Fears](https://www.chapman.edu/wilkinson/research-centers/babbie-center/survey-american-fears.aspx), Public Speaking is AmericaGÇÖs number one fear. (Note 1) ![](/site/images/public-speaking-anxiety/Public%20Speaking%20Anxiety%20optimized.jpg) *I read a thing that actually says that speaking in front of a crowd is* *considered the number one fear of the average person.* *I found that amazing GÇô* *number two was death!* *That means to the average person if you have to be at* *a* *funeral, you would rather be in the casket than doing the eulogy.* Jerry Seinfeld, Comedian The fear of public speaking is real. Speech anxiety, as it is otherwise known, is so well known as a psychological fear that it has its own scientific term: [Wikepedia (Note](https://en.wikipedia.org/wiki/Glossophobia) [2)](https://en.wikipedia.org/wiki/Glossophobia) #### **Glossophobia** Glossophobia or speech anxiety is the fear of public speaking or of speaking in general. The word glossophobia comes from the Greek +¦++ß+¦-â-â+¦ gl+ěssa, meaning tongue, and -ĺ-î+¦++-é phobos, meaning fear or dread. Many people only have this fear, while others may also have social phobia or social anxiety disorder. ## **The Lizard Brain** Public speaking anxiety is a natural, human reaction. Everyone feels some level of anxiety when standing in front of a crowd to give a speech. Even if the thought of speaking in public doesnGÇÖt terrify you, you can understand the fear. You can probably feel the beginnings of that fear in your stomach right now. Having said that, it seems odd that we are so afraid. It is unlikely we will be killed giving a speech. Impaled by the microphone. Lynched by a dissatisfied audienceGÇŞ What do we think will happen to us? The answer, according to Dr. Glenn Croston, author of [The Real Story](https://amzn.to/2DBGD8u) [of](https://amzn.to/2DBGD8u) [Risk](https://amzn.to/2DBGD8u), seems to lie in our past, in our evolution as a social species. In our [lizard](http://99u.com/videos/5822/seth-godin-quieting-the-lizard-brain) [brain](http://99u.com/videos/5822/seth-godin-quieting-the-lizard-brain). *Humans* *were not the largest, fastest, or fiercest animal GÇö early humans* *survived by* *their wits and their ability to collaborate.* *Those that worked* *together well,* *helping others in their group, probably survived and passed on* *traits that* *contributed to social behavior.* *Failure to be a part of the* *social group,* *getting kicked out, probably spelled doom for early humans.* *Anything that* *threatens our status in our social group, like the threat of* *ostracism, feels* *like a very great risk to us.* Dr. Glenn Croston, PhD Biology, Author [''The](https://www.psychologytoday.com/blog/the-real-story-risk/201211/the-thing-we-fear-more-death) [Thing We Fear More Than Death'', Psychology](https://www.psychologytoday.com/blog/the-real-story-risk/201211/the-thing-we-fear-more-death) [Today(Note](https://www.psychologytoday.com/blog/the-real-story-risk/201211/the-thing-we-fear-more-death) [2)](https://www.psychologytoday.com/blog/the-real-story-risk/201211/the-thing-we-fear-more-death) According to Dr. Corston, speaking in public triggers heart palpitations, anxiety and dread because we are afraid of rejection. This fear of public speaking is not simply a fear of embarrassment or judgment, it is a fear of rejection from the group, fear of being ostracized and left to defend for ourselves. *PowerPoint could be the most powerful tool on your computer. But* *itGÇÖs not.* *Countless innovations fail because their champions use PowerPoint* *the way Microsoft wants them to, instead of the right way.* Seth Godin, Best-selling Author ## **A Little Stress is a Good Thing** [Physiological](https://en.wikipedia.org/wiki/Arousal) [arousal](https://en.wikipedia.org/wiki/Arousal) refers to the physical changes that occur when someone is aroused (stressed). These changes include things such as an increased pulse rate, greater alertness, and more energy. Arousal is necessary for everything from scoring goals in hockey and kicking field goals in football to performing well on a test. And it is necessary for delivering a great speech. The adrenaline kick from moderate arousal makes you more motivated, more alert and energized, and ready to perform. Too much arousal can be counter-productive, however. ![](/site/images/public-speaking-anxiety/Arousal%20and%20Performance%20optimized.jpg) [GÇ˙Practice Helps Relieve Anxiety about Public SpeakingGÇ˙, McGraw Hill](https://www.slideheroes.com/public-speaking-anxiety#) [(Note](https://www.slideheroes.com/public-speaking-anxiety#) [3)](https://www.slideheroes.com/public-speaking-anxiety#) The trick then, is simple (to describe). We should not focus on eliminating the feelings of arousal (low levels of nervousness and anxiety), but, instead, work on keeping these feelings in check so that they do not interfere with our ability to speak effectively. The body does what the brain tells it to do. The key to overcoming the fear of speaking in public (overcoming our undesirable and illogical reactions to the idea of public speaking) is to find a way to change our mindset and our physical response. This is not necessarily easy. But it is possible. In fact, thousands of people each year are able to give a speech because they have learned coping skills that help them to control their public speaking anxiety. *There are two types of speakers.* *Those who get nervous and those who are* *liars.* Mark Twain, Author and Humorist ## **Coping With Public Speaking** **Anxiety** **& Stress** The reasons non-academics give for why the prospect of giving a speech gives them anxiety are, roughly, the same as those confirmed via academic research. The major sources or triggers of speech anxiety are (Note 4): - Lack of preparation - The fear of making mistakes - Concerns about appearance - Projections about a lack of audience interest, and - Lack of previous experience speaking in public ## **Speech anxiety triggers** There are really two ways to cope with the stress of speaking in public: - Avoidance:&nbsp;Convert speeches to sit-down style presentations - Stress management:&nbsp;Manage your Mind\\ ### **Avoidance:&nbsp;Convert speeches to** **sit-down style presentations** LetGÇÖs be honest. The most effective way to eliminate the stress of speaking in public is to **not speak in public**. (You should bookmark this article now so you will be able to reference that little tidbit later.) In all seriousness, for many, many people, this is exactly the strategy they adopt. It works. If you MUST give a presentation, you can still use this strategy (but with a twist). Not all presentations are alike. There are State of the Union addresses to the entire nation. TED Talks seen by millions on the web. And then there is the GÇ˙presentationGÇÖ you need to give at your team meeting. Sit-down, McKinsey-style presentations often get lumped into the category of presentations and public speaking. And they are a different breed entirely. They are made sitting down, around a table, updating a project team, or presenting our thinking to our boss. The context of these types of GÇ˙sit-downGÇÖ meetings has a profound effect on the stress they generate. These types of meetings and presentations: - &nbsp; Consist of small groups, in a more intimate setting, seated - &nbsp; Will be more detail oriented - &nbsp; Are more likely to result in discussion, with other people contributing and asking questions - &nbsp; Likely to have the participants holding a hard-copy of the presentation in their hand They can be, for many, considerably less stressful. You can learn to become very good at writing these types of presentations through [presentation](https://www.slideheroes.com/) [training](https://www.slideheroes.com/). Where possible, a useful avoidance mechanism is to convert a GÇ˙public speakingGÇÖ style presentation into a sit-down style presentation. It will have smaller groups, seated around a table, with supporting material that can be referenced. And it will be less stressful. ### **Stress management: Manage your Mind via Cognitive Behavior Therapy** Stress (physiological arousal) is neither inherently positive, nor negative.&nbsp;Positive or negative emotional reactions to stress are a result of how we interpret or react to being aroused. [Cognitive](https://en.wikipedia.org/wiki/Cognitive_behavioral_therapy) [behavioral](https://en.wikipedia.org/wiki/Cognitive_behavioral_therapy) [therapy](https://en.wikipedia.org/wiki/Cognitive_behavioral_therapy) (CBT) is a form of psychotherapy. It works to change unhelpful thinking and behavior. Put simply, re-framing how we think about stress helps reduce stress and anxiety. Some fascinating research on stress in public speaking conducted by [Dr.](https://www.psychologytoday.com/blog/the-many-sides-stress) [Jeremy](https://www.psychologytoday.com/blog/the-many-sides-stress) [Jamieson](https://www.psychologytoday.com/blog/the-many-sides-stress), concluded that GÇŁchanging cognitions produces downstream benefitsGÇĄ. Participants of the study who were placed in stressful public speaking situations, but prepped about the benefits of stress beforehand, exhibited better outcomes than control participants. (Note 5) Simply understanding stress and how it can be helpful helps us reduce and manage speaking anxiety A second important finding came out of this research. People who experience GÇŁgood stressGÇĄ (think excitement) perform better in acute stress situations than those who are calm. As expected, clam individuals outperform those who experience GÇŁbad stressGÇĄ (think fear or threat). The key take away of this is: Advice on relaxation, while helpful, is probably best for speeches that do not require peak performance For an important presentation or speech, re-framing how we think about stress may be a better strategy. ## 8 Steps to Reducing Stress Before Public Speaking ### **Stage One:** **Managing Public Speaking Anxiety before you** **Speak** ### **1: ADOPT RIGHT** **MINDSET: Re-frame a Pessimistic Attitude** - Understand how stress works. Work to accept the need for some stress to perform optimally - Re-frame how you perceive the symptoms of stress (nervousness, butterflies etc.): stress, and its symptoms, are needed for peak performance - Give up the belief that you have to be perfect. None of us are - Remind yourself: when you speak in public, nothing GÇ˙badGÇÖ can happen - Regulate any [negative](http://www.npr.org/sections/health-shots/2014/10/07/353292408/why-saying-is-believing-the-science-of-self-talk) [GÇ˙self-talkGÇÖ.](http://www.npr.org/sections/health-shots/2014/10/07/353292408/why-saying-is-believing-the-science-of-self-talk) No more GÇ˙What if I forget what I want to say?GÇÖ. Instead ask yourself GÇ˙What if they give me a standing ovation?GÇÖ. seriously.&nbsp;(Source 6) ### **2: CREATE** **CONTENT: Develop your Material, Write your Speech** Some people are able to deliver great presentations by GÇ˙winging-itGÇÖ. They improvise. A less stressful approach is to develop your content in advance. After you have spent enough time thinking about, developing, and practicing your presentation you will find you know the content of the deck in-side and out. Some people manage to do an acceptable job just off the back of the preparation in writing the deck. But we recommend developing a script. Practice the script, and then throw it away. - Write your presentation. For most speeches you really only need two or three main ideas - Develop a script ### **3: PRACTICE: Rehearse and Gain Experience** Practice is important. Some people will recommend not practicing as a way of limiting stress. As we spoke of early, avoidance is a viable strategy. But if you canGÇÖt avoid giving the speech, donGÇÖt avoid the practice. Practice, in clinical terms, is a form of exposure therapy. [Exposure](https://now.tufts.edu/news-releases/neuroscientists-determine-how-treatment-anxiety-disorders-silences-fear-neurons) [therapy](https://now.tufts.edu/news-releases/neuroscientists-determine-how-treatment-anxiety-disorders-silences-fear-neurons) [works](https://now.tufts.edu/news-releases/neuroscientists-determine-how-treatment-anxiety-disorders-silences-fear-neurons). - Practice makes perfect. Presenting is a sport that needs training. - Practice your speech delivery out loud, verbalize the complete presentation - Practice clarity, pace of speaking, engaging with audience, making eye-contact - Practice until you memorize your script, then use the script as a safety net - Confidence comes with experience. Public speaking experience will reduce the stress you feel the next time around ### **4: PREPARE: Attend to the details** These small little techniques can play a huge role in controlling the build up of emotions in the lead-up to your speech. - Avoid common presentation mistakes in this article on presentation tips - Set the right tone in advance by sending a thoughtfully written agenda - Exercise - Get some rest - Eat lightly or not at all an hour before the presentation - Avoid too much coffee, too many cigarettes or other mood-altering substances. While they can work, in the short term GÇô regulating the dosage is impossible. - Look your best, dress for success - Prepare a GÇ˙flight-checkGÇÖ to ensure you have everything you need 1 hour before your speech ### **5: RELAX: Stay Calm and Visualize Success** In her book [Train](https://amzn.to/2BXEF28) [Your Mind, Change Your](https://amzn.to/2BXEF28) [Brain](https://amzn.to/2BXEF28), the Wall Street JournalGÇÖs science columnist Sharon BegleyGÇÖs walks readers through experiments showing that, contrary to conventional scientific theory, new neurons are created in the brain every day. Experiments with Buddhist monks suggest it is possible to train the brain to be better at feeling certain emotions. One of the techniques at the center of this [neuroplasticity](https://en.wikipedia.org/wiki/Neuroplasticity) movement is visualization. [It](http://expertenough.com/1898/visualization-works) [works](http://expertenough.com/1898/visualization-works). To help your performance and to establish the right mindset, visualize delivering a successful presentation (the outcome you want). People who suffer from public speaking anxiety tend to fret, and spend their time visualizing the GÇ˙worst-caseGÇÖ outcomes and abysmal failures. Without realizing it, they adopt the exact opposite visualization approach needed for optimal performance! - [Quite](http://zenhabits.net/meditation-for-beginners-20-practical-tips-for-quieting-the-mind/) [your](http://zenhabits.net/meditation-for-beginners-20-practical-tips-for-quieting-the-mind/) [mind](http://zenhabits.net/meditation-for-beginners-20-practical-tips-for-quieting-the-mind/) - Breathe - Laugh - Warm up your voice - Visualize your optimal outcome (a successful presentation) ### **Stage Two: Managing Anxiety during your Speech** ### **6: HUMANIZE THE AUDIENCE: Remember your AudienceGÇÖs Flaws** Your audience is human. They are not perfect. And they want you to succeed. - Remind yourself that your audience has flaws just like you - Assume your audience is friendly (they are) - Assume your audience is there because they are interested in what you have to say (they are) - Love your audience and assume they love you (they do) ### **7: SET THE RIGHT TONE: Be Yourself** Establish the right tone and mood for your speech. Approach your audience and the presentation with an [open](https://amzn.to/2Cgpi91) [heart](https://amzn.to/2Cgpi91). - Adopt the right disposition - Have conviction - Be yourself - Do not perform, instead think of your presentation as a private, one-on-one conversation - Smile ### **Stage Three: Managing Anxiety after your** **Speech** ### **8: UNWIND: Relax** **and Debrief** Even very experienced public speakers and presenters can find themselves in a bit of a mental fog following their speech. It can be hard to concentrate or stay focused afterwards. Critically, what takes place after your presentation will have an important influence on the way you approach and deliver your next speech. - Breathe deeply. This will help to reduce your heart rate. - Minimize self-talk. You can mentally review your presentation later. - Write down any comments, outstanding to-doGÇÖs or feedback for review later. # **Summary** - Anxiety before a presentation or speech is normal. Everyone experiences it. - This physiological response is an inheritance from our caveman ancestors. It is part of our lizard brain. - A little stress is a good thing. It is necessary for peak performance - We can deal with speech anxiety via avoidance or stress management - When possible, convert GÇ˙public speakingGÇÖ style presentations into a sit-down style presentation - We recommend eight steps before, during and after the speech to help manage stress - Smile ## **Footnotes** **& Sources** ### **Footnotes** 1 &nbsp;[Chapman University Survey on](https://www.chapman.edu/wilkinson/research-centers/babbie-center/survey-american-fears.aspx) [American](https://www.chapman.edu/wilkinson/research-centers/babbie-center/survey-american-fears.aspx) [Fears](https://www.chapman.edu/wilkinson/research-centers/babbie-center/survey-american-fears.aspx) 2 &nbsp;Wikipedia on&nbsp;[Glossophobia](https://en.wikipedia.org/wiki/Glossophobia) 3 &nbsp;GÇ˙[Practice Helps Relieve Anxiety about](https://highered.mheducation.com/sites/dl/free/0767430158/43464/bry30158_ch03.pdf) [Public](https://highered.mheducation.com/sites/dl/free/0767430158/43464/bry30158_ch03.pdf) [Speaking](https://highered.mheducation.com/sites/dl/free/0767430158/43464/bry30158_ch03.pdf)GÇ˙, McGraw Hill 4 &nbsp;Amy M. Bippus and John A. Daly, GÇŁ[What Do People](http://www.tandfonline.com/doi/abs/10.1080/03634529909379153#.VdNpG7JVhBc) [Think](http://www.tandfonline.com/doi/abs/10.1080/03634529909379153#.VdNpG7JVhBc) [Causes Stage Fright? Na+»ve Attributions About the Reasons for Public](http://www.tandfonline.com/doi/abs/10.1080/03634529909379153#.VdNpG7JVhBc) [Speaking](http://www.tandfonline.com/doi/abs/10.1080/03634529909379153#.VdNpG7JVhBc) [Anxiety](http://www.tandfonline.com/doi/abs/10.1080/03634529909379153#.VdNpG7JVhBc),GÇĄ Communication Education, 48 (1999): 63GÇô72. 5 &nbsp;GÇ˙[The Many Sides](https://www.psychologytoday.com/blog/the-many-sides-stress) [of](https://www.psychologytoday.com/blog/the-many-sides-stress) [Stress](https://www.psychologytoday.com/blog/the-many-sides-stress)GÇ˙, Dr. Jeremy Jamieson, Psychology Today 6 &nbsp;GÇ˙[Why Saying](http://www.npr.org/sections/health-shots/2014/10/07/353292408/why-saying-is-believing-the-science-of-self-talk) [is](http://www.npr.org/sections/health-shots/2014/10/07/353292408/why-saying-is-believing-the-science-of-self-talk) [Believing](http://www.npr.org/sections/health-shots/2014/10/07/353292408/why-saying-is-believing-the-science-of-self-talk)GÇ˙, NPR 7 &nbsp;GÇ˙[Neuroscientists Determine How Treatment for Anxiety](https://now.tufts.edu/news-releases/neuroscientists-determine-how-treatment-anxiety-disorders-silences-fear-neurons) [Disorders](https://now.tufts.edu/news-releases/neuroscientists-determine-how-treatment-anxiety-disorders-silences-fear-neurons) [Silences](https://now.tufts.edu/news-releases/neuroscientists-determine-how-treatment-anxiety-disorders-silences-fear-neurons) [Fear](https://now.tufts.edu/news-releases/neuroscientists-determine-how-treatment-anxiety-disorders-silences-fear-neurons) [Neurons](https://now.tufts.edu/news-releases/neuroscientists-determine-how-treatment-anxiety-disorders-silences-fear-neurons)GÇ˙, Tufts.edu 8 &nbsp;GÇ˙[Does Visualization Really Work? HereGÇÖs Evidence That](http://expertenough.com/1898/visualization-works) [It](http://expertenough.com/1898/visualization-works) [Does](http://expertenough.com/1898/visualization-works)GÇ˙, Expert Enough ### **Sources** GÇ˙[HBR Guide to Persuasive Presentations](https://amzn.to/2CeybjC)GÇ˙, Nancy Duarte GÇ˙[AmericaGÇÖs Top fears: Public Speaking,&nbsp;heights](https://www.washingtonpost.com/news/wonkblog/wp/2014/10/30/clowns-are-twice-as-scary-to-democrats-as-they-are-to-republicans/) [and](https://www.washingtonpost.com/news/wonkblog/wp/2014/10/30/clowns-are-twice-as-scary-to-democrats-as-they-are-to-republicans/) [bugs](https://www.washingtonpost.com/news/wonkblog/wp/2014/10/30/clowns-are-twice-as-scary-to-democrats-as-they-are-to-republicans/)GÇ˙, Washington Post", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}]}], "direction": "ltr"}, "chunks": [], "config": {"theme": {"text": {"bold": "lexical-bold", "code": "lexical-code", "italic": "lexical-italic", "subscript": "lexical-subscript", "underline": "lexical-underline", "superscript": "lexical-superscript", "strikethrough": "lexical-strikethrough", "underlineStrikethrough": "lexical-underlineStrikethrough"}}, "namespace": "lexical"}, "format": "", "version": 1, "syncedChunksData": {}, "downloadedDataVersions": []}', 'A guide to practical steps you can take to manage the stress of public speaking.', '8e5a8e51-be56-4af0-bb8e-175ffdb7e4f1', '8e5a8e51-be56-4af0-bb8e-175ffdb7e4f1', NULL, NULL, '2025-04-15 18:51:54.012+00', '2025-04-15 18:51:54.013+00', '2025-04-15 18:51:54.013+00', NULL),
	('4bca5918-1673-4ce6-a91d-e9f636532ea1', 'The Best Business Charts: The 6 Most Devastatingly Effecting Business Charts & How To Use Them', 'typology-business-charts', 'published', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "To convince and persuade in todayGÇÖs corporate world business people must construct [evidence-based](https://www.slideheroes.com/mckinsey-business-presentations.html) [arguments](https://www.slideheroes.com/mckinsey-business-presentations.html). They must demonstrate, not simply assert. Using the right business charts during your presentation is essential to demonstrating your point. (and one of my best [presentation](https://www.slideheroes.com/10-business-presentation-tips.html) [tips](https://www.slideheroes.com/10-business-presentation-tips.html)). Even though everyone is familiar with a few basic business charts, most people arenGÇÖt adept at using charts to their fullest data visualization potential. Whiz-bang features like animations or sequentially revealed charts are not the answer. Instead, you need to begin with an understanding of what message or point you want your data to communicate, and which type of chart best illustrates this kind of data-driven point. ![](/site/images/typology-business-charts/business-charts-infographic-optimized.jpg) ## Why ItGÇÖs Critical To Use The Right Business Charts The primary concern while making a presentation is ensuring that your audience will understand the point you are making (the answer to the question you have planted in the mind of the audience). If your audience does not understand your data or does not follow your presentation closely enough due to disengagement, you will not get your point across to them. Your job as presenter is twofold: 1. Present your data accurately, in a manner that conveys your point or message 1. Present your data in a way that makes it easy to understand Making effective business charts goes hand in hand with being able to present those charts effectively. But specific chart types are better at presenting certain data relationships than others. It is critical to understand what data relationship you are trying to highlight, and what chart type best illustrates this type of relationship. ## Why Not Just Use A Table Or A Spreadsheet? Tables and spreadsheets are frequently an effective means of displaying data. The primary benefit of a table is that it makes it easy to look up individual values. The first thing we need to do when trying to determine whether we should use a table or a graph is ask ourselves how the information will be used. If the primary use will be to look up particular values, then a table is a good option. Use Tables when you want to use data to: - Look up individual values - Compare individual values (but not entire series of values) - Present precise values - Present both summary and detail values Because of their visual nature, graphs present the overall shape of the data. Use Graphs when: - The message or story is contained in the shape of the data series - The display will be used to reveal relationships among whole sets of values Knowing when to use a table and when to use a chart is a matter of understanding the type of data youGÇÖre working with, the story you want that data to tell, and the strengths and weaknesses of tables and graphs in presenting data. ## Basic Business Charts And Graphs Graphs display relationships in quantitative information by giving shape to those relationships. Quantitative values can be represented in graphs using the following basic tool-set: - Points (scatter chart, radar chart) - Bars (bar graph, stacked bar graph, column chart, waterfall chart) - Lines (line graph, line chart, gantt chart, combination chart) - Boxes (organizational chart, stacked area chart, marimekko chart, flow chart) - Shapes with varying 2D areas (pie chart, area chart, donut chart) - Shapes with varying color intensity (venn diagram, geospatial maps) ![](/site/images/typology-business-charts/respresenting-quantitative-values-optimized.jpg) ## What Quantitative Relationship Are You Trying To Illustrate? There are 8 types of relationships that we use business charts and graphs to display. When determining what type of graph to select, it is absolutely critical that you first consider what you are trying to say with the data. When you are in the diagnostic phase of your work, you may not know what the data has to say, so you will try a few different approaches. But once it comes time to creating your presentation, the data on the page exists to support the message you have in your slide headline. You will have a very specific message you will want the data to convey. You will have a specific relationship that you will want to represent. LetGÇÖs review which graph types are most appropriate for each of these 8 types of data relationships. ### Nominal Comparison A nominal comparison graph displays a series of discrete quantitative values to highlight their relative size. A nominal comparison is best depicted by a bar chart that compares a small number of variables against the same scale. You can display data either horizontally or vertically, though the standard is to display your data vertically. ### Time Series A time series is a series of quantitative values that feature something changing over time. Daily closing stock prices over the past month and weekly sales over the last year are examples of time series data. In a time series, the X-axis represents time points whereas the Y-axis represents the metric of interest. Line charts do a very good job of displaying the shape of the data over time and are probably the most common time series chart type. Connecting the individual data points with a line visually links the data and creates an emphasis on the shape of the data, rather than individual data points. ### Ranking A ranking graph shows how individual values relate to one another sequentially. Which is the largest? Which is the smallest? Displaying rankings graphically is typically done best with horizontal or vertical bar charts. The key is to sort your data series in ascending or descending order, depending on the main message you want your data to deliver. ### Part-to-Whole Part-to-Whole relationships are relationships where each data point is a fraction of a larger complete data set. Part-to-Whole graphs describe how a part of something relates to the whole. They display the proportion of the whole that each part contributes. Usually it is best to express these proportions as a percentage. ### Deviation A deviation graph displays how one set of values differs to another primary set of values. Imagine comparing budget figures to actuals, for example. Deviation relationships are typically arranged in a series of adjacent bar charts, with the difference between the height of each bar in the same data point being the most attention-grabbing. ### Distribution Distribution graphs show how one or more sets of quantitative values are distributed across their full quantitative range, from lowest to highest. Bar charts work best, though other options can function just as well (e.g. box and whisker graphs). ### Correlation Correlation graphs display the relationship between two paired sets of quantitative values to demonstrate whether they are related or not. The standard way to depict a correlation is via a scatter plot with a line of best fit, which is calculated. ### Geospatial Geospatial graphs display the geographical location of values, positioning values on a map. Because of the constraints of placing values onto a map, we must rely on size, color, color intensity and width to encode quantitative value. ## Select the Right Business Chart Type to Communicate Your Message Asserting something is true in a presentation and using the GÇŁbecause I say soGÇÖ argument as support (either explicitly or implicitly), is a surprisingly common occurrence. And make no mistake, it is a mistake. We need facts. Data. And we need to present those facts in a compelling, effective manner. Sometimes neither a table nor a graph will be appropriate. When the quantitative information you want to display consists of a number or two, text will do just fine. Resist the temptation to sex things up by slapping things into a chart. But when you have a more complex data-driven conclusion to communicate, you need to use either a table or a chart. The critical step is understanding which types of charts and graphs are best suited to communicate the data relationship you want to highlight. ## Summary - To select between a graph or table, determine how the information will be used - The primary benefit of a table is that it makes it easy to look up individual values - Use tables when you want to look up individual values; Compare individual values; Present precise values; Present both summary and detail values - Graphs present the overall shape of the data - Use graphs when the message or story is contained in the shape of the data or when the the display will be used to reveal relationships among whole sets of values - Select the appropriate business chart type based on the data relationship being communicated - Have a look at this presentation from BCG to see how a top consultancy does it ![](/site/images/typology-business-charts/data-relationships-and-charts-optimized.jpg) ## Resources - GÇŁ[Visualize This](https://amzn.to/2CI2pbK)GÇĄ by Nathan Yau - GÇŁ[The Visual Display Of Quantitative Information](https://amzn.to/2DTtMyN)GÇĄ by Edward R. Tufte - GÇŁ[Show Me The Numbers: Designing Tables And Graphs](https://amzn.to/2EGS1Sc) [To](https://amzn.to/2EGS1Sc) [Enlighten](https://amzn.to/2EGS1Sc)GÇĄ by Stephen Few - [https://blog.hubspot.com/marketing/data-visualization-choosing-chart](https://blog.hubspot.com/marketing/data-visualization-choosing-chart) - [https://eazybi.com/blog/data_visualization_and_chart_types/](https://eazybi.com/blog/data_visualization_and_chart_types/) - [https://www.slidegenius.com/blog/4-types-charts-use-business-presentations/](https://www.slidegenius.com/blog/4-types-charts-use-business-presentations/) - [https://infogram.com/page/choose-the-right-chart-data-visualization](https://infogram.com/page/choose-the-right-chart-data-visualization)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}]}], "direction": "ltr"}, "chunks": [], "config": {"theme": {"text": {"bold": "lexical-bold", "code": "lexical-code", "italic": "lexical-italic", "subscript": "lexical-subscript", "underline": "lexical-underline", "superscript": "lexical-superscript", "strikethrough": "lexical-strikethrough", "underlineStrikethrough": "lexical-underlineStrikethrough"}}, "namespace": "lexical"}, "format": "", "version": 1, "syncedChunksData": {}, "downloadedDataVersions": []}', 'Guide and infographic on the most effective charts in business and how to use them.', '9dbc3d2e-1c39-4de3-870f-ff682fbc7f92', '9dbc3d2e-1c39-4de3-870f-ff682fbc7f92', NULL, NULL, '2025-04-15 18:51:54.044+00', '2025-04-15 18:51:54.045+00', '2025-04-15 18:51:54.045+00', NULL),
	('2ae969e6-6731-44c8-af75-38c28a54f559', '4 Powerful Tools to Improve Your Presentation', 'presentation-tools', 'published', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "{% youtube src=\"yk9lXobJ95E\" /%} This is {% highlight variant=\"blue\" %}highlighted{% /highlight %} text {% quote    quote=\"This is the quote\"    citation=\"Michael Smith\"    image=\"/cms/images/presentation-tools/tufte circle optimized.png\" /%} this is more text {% cta    ctatext=\"Ready to get started?\"    ctadescription=\"Join hundreds of satisfied customers and take your presentations to the next level.\"    ctabuttontext=\"Start your free trial\" /%} more text and more test {% bunny bunnyvideoid=\"7e39514a-18fd-41e3-a07b-e1cbf05dd365\" /%} That was a bunny.net video", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}]}], "direction": "ltr"}, "chunks": [], "config": {"theme": {"text": {"bold": "lexical-bold", "code": "lexical-code", "italic": "lexical-italic", "subscript": "lexical-subscript", "underline": "lexical-underline", "superscript": "lexical-superscript", "strikethrough": "lexical-strikethrough", "underlineStrikethrough": "lexical-underlineStrikethrough"}}, "namespace": "lexical"}, "format": "", "version": 1, "syncedChunksData": {}, "downloadedDataVersions": []}', 'Recommended tools that assist in making the process of creating a presentation easier & more efficient.', '1af66bcb-531d-4edd-ac14-4defd31e4086', '1af66bcb-531d-4edd-ac14-4defd31e4086', NULL, NULL, '2024-04-12 00:00:00+00', '2025-04-15 18:51:53.995+00', '2025-04-15 18:51:53.995+00', NULL),
	('8ad9eb9d-516e-4328-b98e-c95b8165aa73', 'Seneca Community College partnership with SlideHeroes', 'seneca-partnership', 'published', '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "# **Partnership with Seneca College** We are thrilled to have partnered with [Seneca College](http://www.senecacollege.ca/home.html) to make the SlideHeroes Presentation Excellence Certification course a core element of SenecaGÇÖs GÇ˙Presenting Complex InformationGÇÖ curriculum. In the video above, Seneca students and instructors describe how SlideHeroes is helping teach students to slay their presentation audiences with structure, story, substance, style and self-confidence. We are looking forward to working with Seneca again this year&nbsp; and wish all the students a fantastic winter term. <video></video>", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}]}], "direction": "ltr"}, "chunks": [], "config": {"theme": {"text": {"bold": "lexical-bold", "code": "lexical-code", "italic": "lexical-italic", "subscript": "lexical-subscript", "underline": "lexical-underline", "superscript": "lexical-superscript", "strikethrough": "lexical-strikethrough", "underlineStrikethrough": "lexical-underlineStrikethrough"}}, "namespace": "lexical"}, "format": "", "version": 1, "syncedChunksData": {}, "downloadedDataVersions": []}', 'Seneca College is Canada''s largest community college. Hear students & instructors describe how SlideHeroes is helping students deliver presentations with structure, story, substance, style & self-confidence.', '16b58b9b-fb52-4969-a079-acd4281107c4', '16b58b9b-fb52-4969-a079-acd4281107c4', NULL, NULL, '2025-04-15 18:51:54.028+00', '2025-04-15 18:51:54.029+00', '2025-04-15 18:51:54.029+00', NULL);
